-- ── Điểm danh bổ sung cho HS seed 12 ─────────────────────────────────────────
DO $$
DECLARE
  v_session RECORD;
  v_enrollment RECORD;
  v_status VARCHAR(30);
  v_seed INT;
BEGIN
  FOR v_enrollment IN
    SELECT e.id AS enrollment_id, e.student_id, e.class_id, e.status
    FROM enrollments e
    WHERE e.id >= '70000000-0000-0000-0000-000000000036'
      AND e.id <= '70000000-0000-0000-0000-000000000055'
      AND e.status IN ('active', 'paused')
  LOOP
    FOR v_session IN
      SELECT s.id AS session_id, s.session_no
      FROM sessions s
      WHERE s.class_id = v_enrollment.class_id
        AND s.status = 'completed'
      ORDER BY s.session_no
    LOOP
      -- Q9: chỉ 2 buổi đầu
      IF v_enrollment.enrollment_id IN (
        '70000000-0000-0000-0000-000000000041',
        '70000000-0000-0000-0000-000000000042'
      ) AND v_session.session_no > 2 THEN
        CONTINUE;
      END IF;

      v_seed := (abs(hashtext(v_enrollment.enrollment_id::text)) + v_session.session_no * 17) % 10;
      v_status := CASE
        WHEN v_enrollment.enrollment_id = '70000000-0000-0000-0000-000000000048'
             AND v_session.session_no BETWEEN 1 AND 4 THEN 'absent_unexcused'
        WHEN v_enrollment.enrollment_id = '70000000-0000-0000-0000-000000000051'
             AND v_session.session_no <= 10 THEN 'present'
        WHEN v_enrollment.enrollment_id = '70000000-0000-0000-0000-000000000046'
             AND v_session.session_no <= 8 THEN 'present'
        WHEN v_enrollment.enrollment_id = '70000000-0000-0000-0000-000000000046'
             AND v_session.session_no > 8 THEN 'absent_excused'
        WHEN v_seed = 0 THEN 'late'
        WHEN v_seed = 1 THEN 'absent_excused'
        ELSE 'present'
      END;

      INSERT INTO attendance (session_id, student_id, enrollment_id, status, recorded_by, recorded_at)
      VALUES (
        v_session.session_id,
        v_enrollment.student_id,
        v_enrollment.enrollment_id,
        v_status,
        '10000000-0000-0000-0000-000000000002',
        now() - INTERVAL '1 day' * v_session.session_no
      )
      ON CONFLICT (session_id, student_id) DO NOTHING;
    END LOOP;
  END LOOP;
END $$;

